SELECT p.*, ste.site_nm AS site_nm, cd_pt.code_label AS plan_type_cd_nm, cd_ps.code_label AS plan_status_cd_nm FROM pm_plan p LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN sy_code cd_pt ON cd_pt.code_grp = 'PLAN_TYPE' AND cd_pt.code_value = p.plan_type_cd LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PLAN_STATUS' AND cd_ps.code_value = p.plan_status_cd
ORDER BY p.plan_id ASC ORDER BY p.plan_id DESC ORDER BY p.plan_nm ASC ORDER BY p.plan_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

